let animais = global.get('animais') || [];
msg.payload = animais;
return msg;

let animais = global.get('animais') || [];
let contador = global.get('contadorAnimal') || 1;

let novosAnimais = Array.isArray(msg.payload) ? msg.payload : [msg.payload];

novosAnimais.forEach(animal => {
    animal.id = contador;
    animal.historicoPeso = animal.historicoPeso || [];
    // Adiciona o peso inicial ao histórico
    if (animal.pesoAtual) {
        animal.historicoPeso.push({
            data: new Date().toISOString().split('T')[0],
            peso: animal.pesoAtual
        });
    }
    // Calcula lucro estimado automaticamente
    animal.lucroEstimado = (animal.valorMercado || 0) - ((animal.custoAlimentacao || 0) * 30);
    contador++;
    animais.push(animal);
});

global.set('animais', animais);
global.set('contadorAnimal', contador);
msg.payload = novosAnimais;
return msg;

let animais = global.get('animais') || [];
let id = msg.req.params.id;

animais = animais.filter(animal => String(animal.id) !== String(id));

global.set('animais', animais);
msg.payload = { mensagem: "Animal removido" };
return msg;

let animais = global.get('animais') || [];
let id = msg.req.params.id;

let index = animais.findIndex(animal => String(animal.id) === String(id));

if (index !== -1) {
    let animalAtual = animais[index];

    // Atualiza os campos
    animais[index] = { ...animalAtual, ...msg.payload, id: animalAtual.id };

    // Se o peso mudou, adiciona ao histórico
    if (msg.payload.pesoAtual && msg.payload.pesoAtual !== animalAtual.pesoAtual) {
        animais[index].historicoPeso = animais[index].historicoPeso || [];
        animais[index].historicoPeso.push({
            data: new Date().toISOString().split('T')[0],
            peso: msg.payload.pesoAtual
        });
    }

    // Recalcula lucro estimado
    animais[index].lucroEstimado = (animais[index].valorMercado || 0) - ((animais[index].custoAlimentacao || 0) * 30);

    global.set('animais', animais);
    msg.payload = animais[index];
} else {
    msg.payload = { erro: "Animal não encontrado" };
}

return msg;

try {
    var textoLimpo = msg.payload.toString().trim();
    var dados = JSON.parse(textoLimpo);

    // ── Sensor de PRESENÇA ──────────────────────────────────────
    if (dados && dados.tipo === "presenca") {
        var temGado = dados.presenca === true;
        global.set('presenca_gado', {
            presenca: temGado,
            distancia_cm: dados.distancia_cm,
            timestamp: new Date().toISOString()
        });
        var statusP = temGado
            ? "GADO DETECTADO (" + dados.distancia_cm + " cm)"
            : "Livre (" + dados.distancia_cm + " cm)";
        node.status({fill: temGado ? "red" : "green", shape: "dot", text: statusP});
        return null;
    }

    // ── Sensor de RAÇÃO ─────────────────────────────────────────
    if (dados && dados.distancia_cm !== undefined) {
        dados.timestamp = new Date().toISOString();
        dados.hora = new Date().toLocaleTimeString();

        // ---- Bloquear medição se houver gado no local ----
        var presencaGado = global.get('presenca_gado') || null;
        if (presencaGado && presencaGado.presenca === true) {
            dados.bloqueado = true;
            dados.motivo_bloqueio = "Gado detectado próximo ao recipiente. Medição de ração indisponível.";
            dados.distancia_cm = null;
            dados.percentual_racao = null;
            dados.peso_kg = null;
            dados.alerta = "BLOQUEADO";
            global.set('ultima_leitura', dados);
            node.status({fill: "red", shape: "ring", text: "BLOQUEADO: gado no local"});
            return null;
        }

        dados.bloqueado = false;

        // ---- Config do recipiente ----
        var config = global.get('config_recipiente') || null;
        var percentualAtual = null;
        var pesoAtual = null;

        if (config && config.distancia_vazio_cm && config.distancia_cheio_cm) {
            var vazio = config.distancia_vazio_cm;
            var cheio = config.distancia_cheio_cm;
            var faixa = vazio - cheio;

            if (faixa > 0) {
                var preenchido = vazio - dados.distancia_cm;
                percentualAtual = (preenchido / faixa) * 100;
                percentualAtual = Math.max(0, Math.min(100, percentualAtual));
                percentualAtual = Math.round(percentualAtual * 10) / 10;

                if (config.capacidade_kg) {
                    pesoAtual = Math.round((percentualAtual / 100) * config.capacidade_kg * 100) / 100;
                }
            }
        }

        dados.percentual_racao = percentualAtual;
        dados.peso_kg = pesoAtual;

        // ---- Alerta ----
        if (percentualAtual !== null) {
            if (percentualAtual <= 15) {
                dados.alerta = "CRITICO";
            } else if (percentualAtual <= 30) {
                dados.alerta = "BAIXO";
            } else {
                dados.alerta = "NORMAL";
            }
        } else {
            dados.alerta = (dados.distancia_cm > 30) ? "CRITICO" : "NORMAL";
        }

        // ---- Consumo desde última leitura ----
        var ultima = global.get('ultima_leitura');
        var consumoDesdeUltima = null;
        if (ultima && ultima.peso_kg !== null && ultima.peso_kg !== undefined && pesoAtual !== null) {
            var diff = ultima.peso_kg - pesoAtual;
            consumoDesdeUltima = diff > 0 ? Math.round(diff * 100) / 100 : 0;
        }
        dados.consumo_desde_ultima_kg = consumoDesdeUltima;

        global.set('ultima_leitura', dados);

        var historico = global.get('historico_leitor') || [];
        historico.unshift(dados);
        if (historico.length > 500) historico = historico.slice(0, 500);
        global.set('historico_leitor', historico);

        var statusTxt = dados.distancia_cm + " cm";
        if (percentualAtual !== null) statusTxt += " | " + percentualAtual + "%";
        statusTxt += " | " + dados.alerta;

        var cor = "green";
        if (dados.alerta === "CRITICO") cor = "red";
        else if (dados.alerta === "BAIXO") cor = "yellow";

        node.status({fill: cor, shape: "dot", text: statusTxt});
    } else {
        node.status({fill: "yellow", shape: "ring", text: "Ignorado: Sem distância"});
    }
} catch (e) {
    node.status({fill: "red", shape: "dot", text: "Erro na leitura do JSON"});
}
return null;

var leitura = global.get('ultima_leitura') || { distancia_cm: null, percentual_racao: null, peso_kg: null, bloqueado: false };
var presenca = global.get('presenca_gado') || { presenca: false, distancia_cm: null, timestamp: null };
msg.payload = {
    leitura: leitura,
    presenca_gado: presenca
};
return msg;

// Espera: { "hora": "14:30", "acao": "adicionar" }  ou  { "hora": "14:30", "acao": "remover" }
// Se 'acao' não vier, assume 'adicionar' (compatível com o formato antigo)
var body = msg.payload || {};
var lista = global.get('horarios_alarme') || [];

if (body.hora) {
    var acao = body.acao || 'adicionar';

    if (acao === 'adicionar') {
        if (lista.indexOf(body.hora) === -1) {
            lista.push(body.hora);
            lista.sort();
        }
    } else if (acao === 'remover') {
        lista = lista.filter(function (h) { return h !== body.hora; });
    }

    global.set('horarios_alarme', lista);
}

msg.payload = { horarios_alarme: lista };
return msg;

var lista = global.get('horarios_alarme') || [];
if (!lista.length) return null;

var agora = new Date();
var horaAtual = agora.getHours().toString().padStart(2, '0') + ":" +
                agora.getMinutes().toString().padStart(2, '0');

if (lista.indexOf(horaAtual) !== -1) {
    msg.payload = "medir";
    return msg;
}
return null;

// Espera: { "distancia_vazio_cm": 40, "distancia_cheio_cm": 5, "capacidade_kg": 20 }
var body = msg.payload || {};
var atual = global.get('config_recipiente') || {};

if (body.distancia_vazio_cm !== undefined) atual.distancia_vazio_cm = Number(body.distancia_vazio_cm);
if (body.distancia_cheio_cm !== undefined) atual.distancia_cheio_cm = Number(body.distancia_cheio_cm);
if (body.capacidade_kg !== undefined) atual.capacidade_kg = Number(body.capacidade_kg);

global.set('config_recipiente', atual);
msg.payload = atual;
return msg;

// Uso: GET /consumo?periodo=dia   ou   ?periodo=semana   ou   ?dias=7
var periodo = (msg.req && msg.req.query && msg.req.query.periodo) || 'dia';
var diasParam = (msg.req && msg.req.query && msg.req.query.dias);

var agora = new Date();
var limite = new Date(agora);

if (diasParam) {
    limite.setDate(agora.getDate() - Number(diasParam));
} else if (periodo === 'semana') {
    limite.setDate(agora.getDate() - 7);
} else if (periodo === 'mes') {
    limite.setDate(agora.getDate() - 30);
} else {
    // dia: desde a meia-noite de hoje
    limite = new Date(agora.getFullYear(), agora.getMonth(), agora.getDate(), 0, 0, 0);
}

var historico = global.get('historico_leitor') || [];

var doPeriodo = historico.filter(function (item) {
    return new Date(item.timestamp) >= limite;
});

// soma todo consumo positivo registrado entre leituras dentro do período
var totalConsumidoKg = 0;
doPeriodo.forEach(function (item) {
    if (item.consumo_desde_ultima_kg) {
        totalConsumidoKg += item.consumo_desde_ultima_kg;
    }
});
totalConsumidoKg = Math.round(totalConsumidoKg * 100) / 100;

// agrupa por dia (YYYY-MM-DD) para exibir gráfico no front
var porDia = {};
doPeriodo.forEach(function (item) {
    var dia = item.timestamp.substring(0, 10);
    porDia[dia] = (porDia[dia] || 0) + (item.consumo_desde_ultima_kg || 0);
});
Object.keys(porDia).forEach(function (d) {
    porDia[d] = Math.round(porDia[d] * 100) / 100;
});

msg.payload = {
    periodo: periodo,
    desde: limite.toISOString(),
    total_consumido_kg: totalConsumidoKg,
    leituras_no_periodo: doPeriodo.length,
    consumo_por_dia: porDia
};
return msg;

var presenca = global.get('presenca_gado') || { presenca: false, distancia_cm: null, timestamp: null };
msg.payload = presenca;
return msg;
